patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..1ac7199ee7a8 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5582,6 +5582,71 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   assert(!CasesB.empty() && "There must be non-default cases.");
   assert(!CasesA.empty() || HasDefault);

+  auto UpdatePHIs = [&](BasicBlock *Succ) {
+    for (auto BBI = Succ->begin(); isa<PHINode>(BBI); ++BBI) {
+      unsigned PreviousEdges = 0;
+      if (Succ == SI->getDefaultDest())
+        ++PreviousEdges;
+      for (auto Case : SI->cases())
+        if (Case.getCaseSuccessor() == Succ)
+          ++PreviousEdges;
+      for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
+        cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
+    }
+  };
+
+  // Recognize switches on ucmp/scmp selecting {lt, eq}/{eq, gt} and rewrite
+  // them as a direct icmp+br before later folds turn them into a select.
+  if (auto *CI = dyn_cast<CmpIntrinsic>(SI->getCondition())) {
+    auto MatchCmpCases = [](SmallVectorImpl<ConstantInt *> &Cases, bool IsGT) {
+      array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
+      return Cases.size() == 2 && Cases[0]->isZero() &&
+             (IsGT ? Cases[1]->isMinusOne() : Cases[1]->isOne());
+    };
+
+    BasicBlock *TrueDest = nullptr;
+    BasicBlock *FalseDest = nullptr;
+    CmpInst::Predicate Pred;
+    if (MatchCmpCases(CasesA, /*IsGT=*/true)) {
+      Pred = CI->getGTPredicate();
+      TrueDest = DestB;
+      FalseDest = DestA;
+    } else if (MatchCmpCases(CasesB, /*IsGT=*/true)) {
+      Pred = CI->getGTPredicate();
+      TrueDest = DestA;
+      FalseDest = DestB;
+    } else if (MatchCmpCases(CasesA, /*IsGT=*/false)) {
+      Pred = CI->getLTPredicate();
+      TrueDest = DestA;
+      FalseDest = DestB;
+    } else if (MatchCmpCases(CasesB, /*IsGT=*/false)) {
+      Pred = CI->getLTPredicate();
+      TrueDest = DestB;
+      FalseDest = DestA;
+    }
+
+    if (TrueDest) {
+      Builder.SetInsertPoint(SI);
+      Value *Cmp =
+          Builder.CreateICmp(Pred, CI->getLHS(), CI->getRHS(), "switch");
+      Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+
+      UpdatePHIs(TrueDest);
+      UpdatePHIs(FalseDest);
+
+      if (!HasDefault)
+        createUnreachableSwitchDefault(SI, DTU);
+
+      auto *UnreachableDefault = SI->getDefaultDest();
+      SI->eraseFromParent();
+
+      if (!HasDefault && DTU)
+        DTU->applyUpdates({{DominatorTree::Delete, BB, UnreachableDefault}});
+
+      return true;
+    }
+  }
+
   // Figure out if one of the sets of cases form a contiguous range.
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
   BasicBlock *ContiguousDest = nullptr;
@@ -7146,6 +7211,32 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
       if (simplifySwitchOnSelect(SI, Select))
         return requestResimplify();

+    // Canonicalize switches on ucmp/scmp to a direct icmp branch when the
+    // switch distinguishes one ordered relation from the other two.
+    if (auto *CI = dyn_cast<CmpIntrinsic>(Cond)) {
+      SmallVector<ConstantInt *, 4> Cases;
+      Cases.reserve(SI->getNumCases());
+      for (auto Case : SI->cases())
+        Cases.push_back(Case.getCaseValue());
+      array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
+
+      std::optional<CmpInst::Predicate> Pred;
+      if (Cases.size() == 2 && Cases[0]->isZero() && Cases[1]->isMinusOne())
+        Pred = CI->getGTPredicate();
+      else if (Cases.size() == 2 && Cases[0]->isZero() && Cases[1]->isOne())
+        Pred = CI->getLTPredicate();
+
+      if (Pred && SI->getDefaultDest()->getSinglePredecessor()) {
+        BasicBlock *CaseDest = SI->case_begin()->getCaseSuccessor();
+        Builder.SetInsertPoint(SI);
+        Value *Cmp =
+            Builder.CreateICmp(*Pred, CI->getLHS(), CI->getRHS(), "switch");
+        Builder.CreateCondBr(Cmp, SI->getDefaultDest(), CaseDest);
+        SI->eraseFromParent();
+        return requestResimplify();
+      }
+    }
+
     // If the block only contains the switch, see if we can fold the block
     // away into any preds.
     if (SI == &*BB->instructionsWithoutDebug(false).begin())

