  7187 |   if (HoistCommon &&
  7188 |       hoistCommonCodeFromSuccessors(SI->getParent(), !Options.HoistCommonInsts))
  7189 |     return requestResimplify();
  7190 | 
  7191 |   return false;
  7192 | }
